// Extract id and optional fields to update
const body = $input.first().json.body;
const id = body.id;

if (!id) {
  throw new Error('id is required');
}

const updateableFields = [
  'nom',
  'email',
  'telephone',
  'raison_sociale',
  'siret',
  'siren',
  'adresse',
  'type',
  'commission_taux_niveau1',
  'commission_taux_niveau2',
  'statut',
  'domaine_personnalise',
  'logo_base64',
  'couleur_primaire',
  'nom_affiche',
  'stripe_connect_id'
];

const fieldsToUpdate = {};

for (const field of updateableFields) {
  if (body.hasOwnProperty(field)) {
    fieldsToUpdate[field] = body[field];
  }
}

return { json: { id, fieldsToUpdate } };

// Build dynamic UPDATE SET clause
const { id, fieldsToUpdate } = $input.first().json;

if (Object.keys(fieldsToUpdate).length === 0) {
  throw new Error('No fields to update');
}

const setClauses = [];
const values = {};

for (const [field, value] of Object.entries(fieldsToUpdate)) {
  setClauses.push(`${field} = \$\{${field}\}`);
  values[field] = value;
}

values.id = id;

const setClause = setClauses.join(', ');

return { json: { setClause, values, id } };
